        self.editor = editor
        self.env = env
        self.require_save = require_save
        self.extension = extension
        self.process_priority = process_priority

    def _priority_popen_kwargs(self) -> dict[str, t.Any]:
        if self.process_priority is None or not WIN:
            return {}

        priority_class = _WIN32_PRIORITY_CLASSES.get(self.process_priority)

        if priority_class is None:
            return {}

        return {"creationflags": priority_class}

    def _apply_process_priority(self, pid: int) -> None:
        if self.process_priority is None or WIN:
            return

        nice_value = _POSIX_NICE_VALUES.get(self.process_priority)

        if nice_value is None:
            return

        try:
            os.setpriority(os.PRIO_PROCESS, pid, nice_value)
        except OSError:
            pass

    def get_editor(self) -> str:
        if self.editor is not None:
            return self.editor
        for key in "VISUAL", "EDITOR":
            rv = os.environ.get(key)
            if rv:
                return rv
        if WIN:
            return "notepad"
        for editor in "sensible-editor", "vim", "nano":
            if os.system(f"which {editor} >/dev/null 2>&1") == 0:
                return editor
        return "vi"

    def edit_files(self, filenames: cabc.Iterable[str]) -> None:
        import subprocess

        editor = self.get_editor()
        environ: dict[str, str] | None = None

        if self.env:
            environ = os.environ.copy()
            environ.update(self.env)

        exc_filenames = " ".join(f'"{filename}"' for filename in filenames)

        try:
            c = subprocess.Popen(
                f"{editor} {exc_filenames}",
                env=environ,
                shell=True,
                **self._priority_popen_kwargs(),
            )
            self._apply_process_priority(c.pid)
            exit_code = c.wait()
            if exit_code != 0:
                raise ClickException(
                    _("{editor}: Editing failed").format(editor=editor)
                )
        except OSError as e:
            raise ClickException(
                _("{editor}: Editing failed: {e}").format(editor=editor, e=e)
            ) from e
